import React, { useEffect, useRef, useState } from 'react';
import './App.css';
import Gun from 'gun';
import 'gun/sea';
// import 'gun/axe';

function App() {

  const gun = Gun('https://gunrelayeurope.herokuapp.com/gun');
  const gameobject = gun.get('gameobject3')

  const player1 = useRef(null);
  const player2 = useRef(null);
  const canvas = useRef(null);

  const [playername, setplayername] = useState('player1')

  // useEffect(() => {
  //   gameobject.put({
  //     player1:{x:50,y:50},
  //     player2:{x:100,y:100}
  //   })
  // }, [])
  

  useEffect(() => {

    gun.get('gameobject3').get('player1').on((data) => {  player1.current=data;console.log(data);})
    gun.get('gameobject3').get('player2').on((data) => { player2.current=data;console.log(data);})
  }, [gun])

  function update() {
    var c = canvas.current.getContext('2d')
    canvas.current.height = window.innerWidth;
    canvas.current.width = window.innerWidth;
    c.clearRect(0, 0, canvas.current.width,canvas.current.height);

    c.fillRect(player1.current.x, player1.current.y, 20, 20)
    c.fillRect(player2.current.x, player2.current.y, 20, 20)

    window.requestAnimationFrame(update)
  }

  useEffect(() => {
    update()
  }, [])



  return (
    <div className="App">
      {/* <p>{first}</p>
      <button onClick={() =>
        jeff.put({
          age: first+1,
          gender: 'male',
          happy: true
        })
      }>BB</button> */}
      <canvas ref={canvas}></canvas>
      <div className='container'>
        <p>Enter your name</p>
        <button onClick={()=>setplayername('player1')}>player1</button>
        <button onClick={()=>setplayername('player2')}>player2</button>
        <div className='controls'>
          <button className='button' onClick={() => {var obj = playername=='player1' ? player1.current : player2.current ; gameobject.get(playername).put( { x: obj.x-5, y: obj.y-5} )}}>\</button>
          <button className='button' onClick={() => {var obj = playername=='player1' ? player1.current : player2.current ; gameobject.get(playername).put( { x: obj.x, y: obj.y-5}   )}}>I</button>
          <button className='button' onClick={() => {var obj = playername=='player1' ? player1.current : player2.current ; gameobject.get(playername).put( { x: obj.x+5, y: obj.y-5} )}}>/</button>
          <button className='button' onClick={() => {var obj = playername=='player1' ? player1.current : player2.current ; gameobject.get(playername).put( { x: obj.x-5, y: obj.y}   )}}>-</button>
          <button className='button' onClick={() => {var obj = playername=='player1' ? player1.current : player2.current ; gameobject.get(playername).put( { x: 0, y: 0}             )}}>O</button>
          <button className='button' onClick={() => {var obj = playername=='player1' ? player1.current : player2.current ; gameobject.get(playername).put( { x: obj.x+5, y: obj.y}   )}}>-</button>
          <button className='button' onClick={() => {var obj = playername=='player1' ? player1.current : player2.current ; gameobject.get(playername).put( { x: obj.x-5, y: obj.y+5} )}}>/</button>
          <button className='button' onClick={() => {var obj = playername=='player1' ? player1.current : player2.current ; gameobject.get(playername).put( { x: obj.x, y: obj.y+5}   )}}>I</button>
          <button className='button' onClick={() => {var obj = playername=='player1' ? player1.current : player2.current ; gameobject.get(playername).put( { x: obj.x+5, y: obj.y+5} )}}>\</button>
        </div>
      </div>
    </div>
  );
}

export default App;
